parameters.functionCode:
// open.er-api returns rates expressed as 'INR -> CODE' (1 INR = N CODE).
// public.currencies.fx_rate is 'CODE -> INR' (1 CODE = N INR). Invert.
const input = $json;
const rates = (input && input.rates) || {};
const out = {};
const targets = ['INR', 'USD', 'SGD', 'AED', 'GBP', 'EUR'];
for (const code of targets) {
  const r = Number(rates[code]);
  if (code === 'INR') { out[code] = 1; continue; }
  if (!r || !isFinite(r) || r <= 0) continue;
  out[code] = Number((1 / r).toFixed(8));
}
return [{ json: { p_rates: out } }];
